def main():
    created = 0
    for relpath, b64data in FILES.items():
        dirname = os.path.dirname(relpath)
        if dirname:
            os.makedirs(dirname, exist_ok=True)
        content = base64.b64decode(b64data)
        # Only write if file doesn't exist or content differs
        write = True
        if os.path.exists(relpath):
            with open(relpath, 'rb') as f:
                if f.read() == content:
                    write = False
        if write:
            with open(relpath, 'wb') as f:
                f.write(content)
            created += 1
    print(f"Bootstrap complete: {created}/{len(FILES)} files written")
    # Create __init__.py for models directory
    os.makedirs('src/llms/models', exist_ok=True)
    init_path = 'src/llms/models/__init__.py'
    if not os.path.exists(init_path):
        with open(init_path, 'w') as f:
            f.write('')

if __name__ == '__main__':
    main()
